// TestClientState_SubscribeCommand_CombinedFilters verifies combined filtering
func TestClientState_SubscribeCommand_CombinedFilters(t *testing.T) {
	state := newClientState()

	// Subscribe to: log_entry only, WARN level, processor source only
	state.UpdateSubscription(
		[]string{"log_entry"},
		"WARN",
		[]string{"processor"},
	)

	// Should receive log_entry from processor with WARN level
	assert.True(t, state.IsSubscribed("log_entry"))
	assert.True(t, state.ShouldReceiveLogLevel("WARN"))
	assert.True(t, state.ShouldReceiveSource("processor"))

	// Should NOT receive other message types
	assert.False(t, state.IsSubscribed("flow_status"))
	assert.False(t, state.IsSubscribed("component_health"))

	// Should NOT receive DEBUG/INFO logs
	assert.False(t, state.ShouldReceiveLogLevel("DEBUG"))
	assert.False(t, state.ShouldReceiveLogLevel("INFO"))

	// Should receive ERROR logs (ERROR >= WARN)
	assert.True(t, state.ShouldReceiveLogLevel("ERROR"))

	// Should NOT receive logs from other sources
	assert.False(t, state.ShouldReceiveSource("gateway"))
	assert.False(t, state.ShouldReceiveSource("udp-input"))
}

