// TestMessageFiltering_LogLevelHierarchy verifies log level filtering hierarchy
func TestMessageFiltering_LogLevelHierarchy(t *testing.T) {
	// Verify that log levels follow hierarchy: DEBUG < INFO < WARN < ERROR
	levels := []string{"DEBUG", "INFO", "WARN", "ERROR"}

	for i, minLevel := range levels {
		t.Run("min_level_"+minLevel, func(t *testing.T) {
			state := newClientState()
			state.UpdateSubscription(nil, minLevel, nil)

			for j, testLevel := range levels {
				allowed := state.ShouldReceiveLogLevel(testLevel)
				if j >= i {
					assert.True(t, allowed, "%s should allow %s", minLevel, testLevel)
				} else {
					assert.False(t, allowed, "%s should filter %s", minLevel, testLevel)
				}
			}
		})
	}
}

