// TestHealthTicker_SendsHealthEnvelopes verifies healthTicker sends component_health envelopes
func TestHealthTicker_SendsHealthEnvelopes(t *testing.T) {
	tests := []struct {
		name           string
		components     map[string]*component.ManagedComponent
		wantEnvelopes  int
		checkPayload   bool
		expectHealthy  bool
		expectedCompID string
	}{
		{
			name: "sends health for single component",
			components: map[string]*component.ManagedComponent{
				"test-comp": {
					Component: &mockComponent{
						metadata: component.Metadata{Name: "test-comp", Type: "processor"},
						health: component.HealthStatus{
							Healthy: true,
							Status:  "running",
						},
					},
					State: component.StateStarted,
				},
			},
			wantEnvelopes:  1,
			checkPayload:   true,
			expectHealthy:  true,
			expectedCompID: "test-comp",
		},
		{
			name: "sends health for multiple components",
			components: map[string]*component.ManagedComponent{
				"comp-1": {
					Component: &mockComponent{
						metadata: component.Metadata{Name: "comp-1", Type: "input"},
						health:   component.HealthStatus{Healthy: true, Status: "running"},
					},
					State: component.StateStarted,
				},
				"comp-2": {
					Component: &mockComponent{
						metadata: component.Metadata{Name: "comp-2", Type: "processor"},
						health:   component.HealthStatus{Healthy: true, Status: "running"},
					},
					State: component.StateStarted,
				},
			},
			wantEnvelopes: 1, // Single envelope with all components
			checkPayload:  false,
		},
		{
			name:          "sends empty health when no components",
			components:    map[string]*component.ManagedComponent{},
			wantEnvelopes: 1,
			checkPayload:  false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
			defer cancel()

			mockCompMgr := &streamMockComponentManager{
				components: tt.components,
			}

			// Channel to receive envelopes
			envelopeChan := make(chan StatusStreamEnvelope, 10)

			// Mock healthTicker function (Builder will implement)
			// This test verifies the contract, not the implementation
			ticker := time.NewTicker(50 * time.Millisecond)
			defer ticker.Stop()

			receivedCount := 0
			timeout := time.After(500 * time.Millisecond)

			// Simulate healthTicker behavior
			go func() {
				for {
					select {
					case <-ticker.C:
						// Get health from component manager
						health := mockCompMgr.GetManagedComponents()

						// Create envelope
						envelope := StatusStreamEnvelope{
							Type:      "component_health",
							ID:        generateTestMessageID(),
							Timestamp: time.Now().UnixMilli(),
							FlowID:    "test-flow",
							Payload:   marshalHealthPayload(t, health),
						}

						select {
						case envelopeChan <- envelope:
						case <-ctx.Done():
							return
						}
					case <-ctx.Done():
						return
					}
				}
			}()

			// Collect envelopes
			for {
				select {
				case envelope := <-envelopeChan:
					// Verify envelope structure
					assert.Equal(t, "component_health", envelope.Type)
					assert.NotEmpty(t, envelope.ID)
					assert.NotEmpty(t, envelope.FlowID)
					assert.Greater(t, envelope.Timestamp, int64(0))

					if tt.checkPayload {
						// Verify payload contains expected component
						var payload map[string]interface{}
						err := json.Unmarshal(envelope.Payload, &payload)
						require.NoError(t, err)
						assert.NotNil(t, payload)
					}

					receivedCount++
					if receivedCount >= tt.wantEnvelopes {
						return
					}

				case <-timeout:
					t.Fatalf("timeout: expected %d envelopes, got %d", tt.wantEnvelopes, receivedCount)
				case <-ctx.Done():
					t.Fatalf("context cancelled: expected %d envelopes, got %d", tt.wantEnvelopes, receivedCount)
				}
			}
		})
	}
}

