// TestFlowWatcher_SendsStatusOnChange verifies flowWatcher sends status only when state changes
func TestFlowWatcher_SendsStatusOnChange(t *testing.T) {
	tests := []struct {
		name          string
		initialState  flowstore.RuntimeState
		updatedState  flowstore.RuntimeState
		wantEnvelopes int
		expectChange  bool
	}{
		{
			name:          "sends on state change",
			initialState:  flowstore.StateDeployedStopped,
			updatedState:  flowstore.StateRunning,
			wantEnvelopes: 1,
			expectChange:  true,
		},
		{
			name:          "does not send when state unchanged",
			initialState:  flowstore.StateRunning,
			updatedState:  flowstore.StateRunning,
			wantEnvelopes: 0,
			expectChange:  false,
		},
		{
			name:          "sends on not deployed to running",
			initialState:  flowstore.StateNotDeployed,
			updatedState:  flowstore.StateRunning,
			wantEnvelopes: 1,
			expectChange:  true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
			defer cancel()

			mockStore := &streamMockFlowStore{
				flows: map[string]*flowstore.Flow{
					"test-flow": {
						ID:           "test-flow",
						Name:         "Test Flow",
						RuntimeState: tt.initialState,
					},
				},
			}

			envelopeChan := make(chan StatusStreamEnvelope, 10)

			// Track previous state
			prevState := tt.initialState

			// Simulate flowWatcher
			ticker := time.NewTicker(50 * time.Millisecond)
			defer ticker.Stop()

			receivedCount := 0

			// Update flow state after first tick
			go func() {
				time.Sleep(100 * time.Millisecond)
				mockStore.mu.Lock()
				mockStore.flows["test-flow"].RuntimeState = tt.updatedState
				mockStore.mu.Unlock()
			}()

			// Run watcher
			go func() {
				for {
					select {
					case <-ticker.C:
						flow, err := mockStore.Get(ctx, "test-flow")
						if err != nil {
							continue
						}

						// Only send if state changed
						if flow.RuntimeState != prevState {
							envelope := StatusStreamEnvelope{
								Type:      "flow_status",
								ID:        generateTestMessageID(),
								Timestamp: time.Now().UnixMilli(),
								FlowID:    "test-flow",
								Payload:   marshalFlowStatusPayload(t, string(flow.RuntimeState), string(prevState)),
							}

							select {
							case envelopeChan <- envelope:
								prevState = flow.RuntimeState
							case <-ctx.Done():
								return
							}
						}
					case <-ctx.Done():
						return
					}
				}
			}()

			// Collect envelopes with timeout
			timeout := time.After(500 * time.Millisecond)

			for {
				select {
				case envelope := <-envelopeChan:
					assert.Equal(t, "flow_status", envelope.Type)
					assert.NotEmpty(t, envelope.ID)

					// Verify payload contains state transition
					var payload map[string]interface{}
					err := json.Unmarshal(envelope.Payload, &payload)
					require.NoError(t, err)
					assert.Equal(t, string(tt.updatedState), payload["state"])
					assert.Equal(t, string(tt.initialState), payload["prev_state"])

					receivedCount++

				case <-timeout:
					assert.Equal(t, tt.wantEnvelopes, receivedCount, "unexpected envelope count")
					return

				case <-ctx.Done():
					t.Fatal("context cancelled")
				}
			}
		})
	}
}

