// TestLogStreamer_ForwardsLogMessages verifies logStreamer forwards log messages as envelopes
func TestLogStreamer_ForwardsLogMessages(t *testing.T) {
	tests := []struct {
		name        string
		subject     string
		logLevel    string
		source      string
		message     string
		wantForward bool
	}{
		{
			name:        "forwards INFO log from processor",
			subject:     "logs.processor.INFO",
			logLevel:    "INFO",
			source:      "processor",
			message:     "test log message",
			wantForward: true,
		},
		{
			name:        "forwards ERROR log from gateway",
			subject:     "logs.gateway.ERROR",
			logLevel:    "ERROR",
			source:      "gateway",
			message:     "error occurred",
			wantForward: true,
		},
		{
			name:        "forwards DEBUG log from system",
			subject:     "logs.system.DEBUG",
			logLevel:    "DEBUG",
			source:      "system",
			message:     "debug info",
			wantForward: true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
			defer cancel()

			mockNATS := &streamMockNATSClient{
				subscriptions: make(map[string]func(context.Context, []byte)),
			}

			envelopeChan := make(chan StatusStreamEnvelope, 10)

			// Subscribe to logs
			err := mockNATS.Subscribe(ctx, "logs.>", func(ctx context.Context, data []byte) {
				// Parse log entry
				var logEntry map[string]interface{}
				if err := json.Unmarshal(data, &logEntry); err != nil {
					return
				}

				// Create envelope
				envelope := StatusStreamEnvelope{
					Type:      "log_entry",
					ID:        generateTestMessageID(),
					Timestamp: time.Now().UnixMilli(),
					FlowID:    "test-flow",
					Payload:   data,
				}

				select {
				case envelopeChan <- envelope:
				case <-ctx.Done():
				}
			})
			require.NoError(t, err)

			// Publish log message
			logData := map[string]interface{}{
				"level":   tt.logLevel,
				"source":  tt.source,
				"message": tt.message,
			}
			logBytes, err := json.Marshal(logData)
			require.NoError(t, err)

			err = mockNATS.Publish(ctx, tt.subject, logBytes)
			require.NoError(t, err)

			// Wait for envelope
			select {
			case envelope := <-envelopeChan:
				assert.Equal(t, "log_entry", envelope.Type)
				assert.NotEmpty(t, envelope.ID)

				var payload map[string]interface{}
				err := json.Unmarshal(envelope.Payload, &payload)
				require.NoError(t, err)
				assert.Equal(t, tt.logLevel, payload["level"])
				assert.Equal(t, tt.source, payload["source"])
				assert.Equal(t, tt.message, payload["message"])

			case <-time.After(500 * time.Millisecond):
				if tt.wantForward {
					t.Fatal("timeout waiting for log envelope")
				}
			case <-ctx.Done():
				t.Fatal("context cancelled")
			}
		})
	}
}

