// TestSubscribeCommand_JSONMarshaling verifies SubscribeCommand marshaling/unmarshaling
func TestSubscribeCommand_JSONMarshaling(t *testing.T) {
	tests := []struct {
		name         string
		command      SubscribeCommand
		jsonStr      string
		wantCommand  string
		wantTypes    []string
		wantLogLevel string
		wantSources  []string
	}{
		{
			name: "full command with all fields",
			command: SubscribeCommand{
				Command:      "subscribe",
				MessageTypes: []string{"flow_status", "log_entry"},
				LogLevel:     "WARN",
				Sources:      []string{"processor", "gateway"},
			},
			wantCommand:  "subscribe",
			wantTypes:    []string{"flow_status", "log_entry"},
			wantLogLevel: "WARN",
			wantSources:  []string{"processor", "gateway"},
		},
		{
			name: "partial command - only message_types",
			command: SubscribeCommand{
				Command:      "subscribe",
				MessageTypes: []string{"component_health"},
			},
			wantCommand:  "subscribe",
			wantTypes:    []string{"component_health"},
			wantLogLevel: "",
			wantSources:  nil,
		},
		{
			name: "partial command - only log_level",
			command: SubscribeCommand{
				Command:  "subscribe",
				LogLevel: "ERROR",
			},
			wantCommand:  "subscribe",
			wantTypes:    nil,
			wantLogLevel: "ERROR",
			wantSources:  nil,
		},
		{
			name: "partial command - only sources",
			command: SubscribeCommand{
				Command: "subscribe",
				Sources: []string{"udp-input"},
			},
			wantCommand:  "subscribe",
			wantTypes:    nil,
			wantLogLevel: "",
			wantSources:  []string{"udp-input"},
		},
		{
			name: "empty command - just command field",
			command: SubscribeCommand{
				Command: "subscribe",
			},
			wantCommand:  "subscribe",
			wantTypes:    nil,
			wantLogLevel: "",
			wantSources:  nil,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Marshal to JSON
			data, err := json.Marshal(tt.command)
			require.NoError(t, err)
			assert.NotEmpty(t, data)

			// Unmarshal back
			var decoded SubscribeCommand
			err = json.Unmarshal(data, &decoded)
			require.NoError(t, err)

			// Verify fields
			assert.Equal(t, tt.wantCommand, decoded.Command)
			assert.Equal(t, tt.wantTypes, decoded.MessageTypes)
			assert.Equal(t, tt.wantLogLevel, decoded.LogLevel)
			assert.Equal(t, tt.wantSources, decoded.Sources)
		})
	}
}

