// TestSubscribeCommand_UpdatesClientState verifies commands update ClientState correctly
func TestSubscribeCommand_UpdatesClientState(t *testing.T) {
	tests := []struct {
		name                string
		initialState        *ClientState
		command             SubscribeCommand
		verifyMessageTypes  map[string]bool
		verifyLogLevel      string
		verifySources       map[string]bool
		testLogLevel        string
		wantLogLevelAllowed bool
		testSource          string
		wantSourceAllowed   bool
	}{
		{
			name:         "full subscription updates all filters",
			initialState: newClientState(),
			command: SubscribeCommand{
				Command:      "subscribe",
				MessageTypes: []string{"log_entry"},
				LogLevel:     "ERROR",
				Sources:      []string{"processor"},
			},
			verifyMessageTypes: map[string]bool{
				"log_entry":         true,
				"flow_status":       false,
				"component_health":  false,
				"component_metrics": false,
			},
			verifyLogLevel:      "ERROR",
			verifySources:       map[string]bool{"processor": true},
			testLogLevel:        "INFO",
			wantLogLevelAllowed: false, // ERROR filter blocks INFO
			testSource:          "gateway",
			wantSourceAllowed:   false, // processor filter blocks gateway
		},
		{
			name:         "partial subscription - only message_types",
			initialState: newClientState(),
			command: SubscribeCommand{
				Command:      "subscribe",
				MessageTypes: []string{"flow_status", "component_health"},
			},
			verifyMessageTypes: map[string]bool{
				"flow_status":       true,
				"component_health":  true,
				"component_metrics": false,
				"log_entry":         false,
			},
			verifyLogLevel:      "",
			verifySources:       nil,
			testLogLevel:        "DEBUG",
			wantLogLevelAllowed: true, // no filter = allow all
			testSource:          "any-source",
			wantSourceAllowed:   true, // no filter = allow all
		},
		{
			name:         "partial subscription - only log_level",
			initialState: newClientState(),
			command: SubscribeCommand{
				Command:  "subscribe",
				LogLevel: "WARN",
			},
			verifyMessageTypes: map[string]bool{
				"flow_status":       true, // default unchanged
				"component_health":  true,
				"component_metrics": true,
				"log_entry":         true,
			},
			verifyLogLevel:      "WARN",
			verifySources:       nil,
			testLogLevel:        "INFO",
			wantLogLevelAllowed: false, // WARN blocks INFO
			testSource:          "any-source",
			wantSourceAllowed:   true, // no filter = allow all
		},
		{
			name:         "partial subscription - only sources",
			initialState: newClientState(),
			command: SubscribeCommand{
				Command: "subscribe",
				Sources: []string{"udp-input", "gateway"},
			},
			verifyMessageTypes: map[string]bool{
				"flow_status":       true, // default unchanged
				"component_health":  true,
				"component_metrics": true,
				"log_entry":         true,
			},
			verifyLogLevel:      "",
			verifySources:       map[string]bool{"udp-input": true, "gateway": true},
			testLogLevel:        "DEBUG",
			wantLogLevelAllowed: true, // no filter = allow all
			testSource:          "processor",
			wantSourceAllowed:   false, // not in whitelist
		},
		{
			name:         "multiple sequential commands stack correctly",
			initialState: newClientState(),
			command: SubscribeCommand{
				Command:      "subscribe",
				MessageTypes: []string{"log_entry"},
			},
			verifyMessageTypes: map[string]bool{
				"log_entry":         true,
				"flow_status":       false,
				"component_health":  false,
				"component_metrics": false,
			},
			verifyLogLevel:      "",
			verifySources:       nil,
			testLogLevel:        "DEBUG",
			wantLogLevelAllowed: true,
			testSource:          "any-source",
			wantSourceAllowed:   true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			state := tt.initialState

			// Apply command
			state.UpdateSubscription(
				tt.command.MessageTypes,
				tt.command.LogLevel,
				tt.command.Sources,
			)

			// Verify message type subscriptions
			for msgType, wantSubscribed := range tt.verifyMessageTypes {
				assert.Equal(t, wantSubscribed, state.IsSubscribed(msgType),
					"unexpected subscription state for %s", msgType)
			}

			// Verify log level filter
			allowed := state.ShouldReceiveLogLevel(tt.testLogLevel)
			assert.Equal(t, tt.wantLogLevelAllowed, allowed,
				"unexpected log level filtering for %s", tt.testLogLevel)

			// Verify source filter
			allowed = state.ShouldReceiveSource(tt.testSource)
			assert.Equal(t, tt.wantSourceAllowed, allowed,
				"unexpected source filtering for %s", tt.testSource)
		})
	}
}

// TestHandleCommand_Subscribe verifies handleCommand processes subscribe commands
func TestHandleCommand_Subscribe(t *testing.T) {
	tests := []struct {
		name             string
		commandJSON      string
		wantErr          bool
		verifySubscribed []string
		verifyFiltered   []string
		verifyLogLevel   string
		verifySources    []string
	}{
		{
			name: "valid subscribe command updates state",
			commandJSON: `{
				"command": "subscribe",
				"message_types": ["flow_status"],
				"log_level": "WARN",
				"sources": ["processor"]
			}`,
			wantErr:          false,
			verifySubscribed: []string{"flow_status"},
			verifyFiltered:   []string{"component_health", "log_entry", "component_metrics"},
			verifyLogLevel:   "WARN",
			verifySources:    []string{"processor"},
		},
		{
			name: "subscribe with only message_types",
			commandJSON: `{
				"command": "subscribe",
				"message_types": ["log_entry", "component_metrics"]
			}`,
			wantErr:          false,
			verifySubscribed: []string{"log_entry", "component_metrics"},
			verifyFiltered:   []string{"flow_status", "component_health"},
			verifyLogLevel:   "",
			verifySources:    nil,
		},
		{
			name: "subscribe with empty filters resets to defaults",
			commandJSON: `{
				"command": "subscribe",
				"message_types": []
			}`,
			wantErr:          false,
			verifySubscribed: []string{}, // explicitly empty
			verifyFiltered:   []string{"flow_status", "component_health", "log_entry", "component_metrics"},
			verifyLogLevel:   "",
			verifySources:    nil,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			state := newClientState()

			// Parse command
			var cmd SubscribeCommand
			err := json.Unmarshal([]byte(tt.commandJSON), &cmd)
			require.NoError(t, err)

			// Handle command (Builder will implement handleCommand function)
			// For now, directly call UpdateSubscription
			state.UpdateSubscription(cmd.MessageTypes, cmd.LogLevel, cmd.Sources)

			// Verify subscribed types
			for _, msgType := range tt.verifySubscribed {
				assert.True(t, state.IsSubscribed(msgType),
					"should be subscribed to %s", msgType)
			}

			// Verify filtered types
			for _, msgType := range tt.verifyFiltered {
				assert.False(t, state.IsSubscribed(msgType),
					"should not be subscribed to %s", msgType)
			}

			// Verify log level
			state.mu.RLock()
			actualLogLevel := state.logLevel
			state.mu.RUnlock()
			assert.Equal(t, tt.verifyLogLevel, actualLogLevel)

			// Verify sources
			if tt.verifySources != nil {
				for _, source := range tt.verifySources {
					assert.True(t, state.ShouldReceiveSource(source),
						"should receive source %s", source)
				}
			}
		})
	}
}

// TestHandleCommand_UnknownCommand verifies graceful handling of unknown commands
func TestHandleCommand_UnknownCommand(t *testing.T) {
	tests := []struct {
		name        string
		commandJSON string
		shouldPanic bool
	}{
		{
			name:        "unknown command type is ignored",
			commandJSON: `{"command": "unknown_action"}`,
			shouldPanic: false,
		},
		{
			name:        "typo in command field",
			commandJSON: `{"command": "subscrib"}`,
			shouldPanic: false,
		},
		{
			name:        "completely unknown command",
			commandJSON: `{"command": "delete_everything"}`,
			shouldPanic: false,
		},
		{
			name:        "empty command field",
			commandJSON: `{"command": ""}`,
			shouldPanic: false,
		},
		{
			name:        "missing command field",
			commandJSON: `{"message_types": ["flow_status"]}`,
			shouldPanic: false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			state := newClientState()
			initialSubscriptions := map[string]bool{
				"flow_status":       state.IsSubscribed("flow_status"),
				"component_health":  state.IsSubscribed("component_health"),
				"component_metrics": state.IsSubscribed("component_metrics"),
				"log_entry":         state.IsSubscribed("log_entry"),
			}

			// Parse command
			var cmd SubscribeCommand
			err := json.Unmarshal([]byte(tt.commandJSON), &cmd)
			require.NoError(t, err) // JSON is valid, just command is unknown

			// Handle command - should not panic
			// Builder must implement handleCommand to ignore unknown commands
			if cmd.Command == "subscribe" {
				state.UpdateSubscription(cmd.MessageTypes, cmd.LogLevel, cmd.Sources)
			}
			// If not "subscribe", ignore (no action)

			// If command was not "subscribe", state should be unchanged
			if cmd.Command != "subscribe" {
				for msgType, wasSubscribed := range initialSubscriptions {
					assert.Equal(t, wasSubscribed, state.IsSubscribed(msgType),
						"subscription should not change for unknown command")
				}
			}
		})
	}
}

