// TestSubscribeCommand_MultipleSequentialCommands verifies multiple commands update state correctly
func TestSubscribeCommand_MultipleSequentialCommands(t *testing.T) {
	state := newClientState()

	// Command 1: Subscribe to flow_status only
	cmd1 := SubscribeCommand{
		Command:      "subscribe",
		MessageTypes: []string{"flow_status"},
	}
	state.UpdateSubscription(cmd1.MessageTypes, cmd1.LogLevel, cmd1.Sources)

	assert.True(t, state.IsSubscribed("flow_status"))
	assert.False(t, state.IsSubscribed("log_entry"))

	// Command 2: Add log level filter (should keep message_types from cmd1)
	cmd2 := SubscribeCommand{
		Command:  "subscribe",
		LogLevel: "ERROR",
	}
	state.UpdateSubscription(cmd2.MessageTypes, cmd2.LogLevel, cmd2.Sources)

	// Message types should remain from cmd1 (flow_status only)
	// UNLESS cmd2.MessageTypes is nil (then it should reset to default)
	// Per plan: partial updates only update specified fields

	// This is a design decision - test documents the expected behavior
	// Builder must ensure consistent behavior

	assert.False(t, state.ShouldReceiveLogLevel("INFO"), "ERROR filter should block INFO")
	assert.True(t, state.ShouldReceiveLogLevel("ERROR"), "ERROR filter should allow ERROR")

	// Command 3: Change message types
	cmd3 := SubscribeCommand{
		Command:      "subscribe",
		MessageTypes: []string{"log_entry", "component_metrics"},
	}
	state.UpdateSubscription(cmd3.MessageTypes, cmd3.LogLevel, cmd3.Sources)

	assert.False(t, state.IsSubscribed("flow_status"))
	assert.True(t, state.IsSubscribed("log_entry"))
	assert.True(t, state.IsSubscribed("component_metrics"))
}

// TestClientState_ConcurrentCommandUpdates verifies thread-safe command handling
func TestClientState_ConcurrentCommandUpdates(t *testing.T) {
	state := newClientState()
	var wg sync.WaitGroup

	numGoroutines := 10
	numUpdates := 100

	wg.Add(numGoroutines)

	for i := 0; i < numGoroutines; i++ {
		go func(id int) {
			defer wg.Done()

			for j := 0; j < numUpdates; j++ {
				// Alternate between different subscriptions
				if j%2 == 0 {
					state.UpdateSubscription(
						[]string{"flow_status"},
						"INFO",
						[]string{"processor"},
					)
				} else {
					state.UpdateSubscription(
						[]string{"log_entry"},
						"ERROR",
						[]string{"gateway"},
					)
				}

				// Read state concurrently
				_ = state.IsSubscribed("flow_status")
				_ = state.ShouldReceiveLogLevel("WARN")
				_ = state.ShouldReceiveSource("processor")
			}
		}(i)
	}

	// Should not panic or race
	wg.Wait()

	// Final state should be valid (one of the two subscription states)
	// We don't know which one, but it should be internally consistent
	isFlowStatus := state.IsSubscribed("flow_status")
	isLogEntry := state.IsSubscribed("log_entry")

	// Should be one or the other (XOR)
	assert.True(t, isFlowStatus != isLogEntry,
		"should be subscribed to either flow_status or log_entry, not both or neither")
}
